locations.new_snippet:
try {
  await workflowApi.saveDraft(f.businessType, { name: f.name, description: f.description, definition: { nodes: [], edges: [] } });
  setMsg(`"${f.name}"已初始化，跳转设计器中…`);
  navigate(`/workflow-designer?businessType=${f.businessType}`);
} catch (e) {
  const errMsg = e instanceof Error ? e.message : '';
  setErr(`"${f.name}"初始化失败${errMsg ? '：' + errMsg : '，请稍后手动发布'}`);
}
